def esc(s):
    return s.replace("'", "\\'")

def gen_items(prefix, items_list):
    lines = []
    n = len(items_list)
    for i, (ch, name, content) in enumerate(items_list, 1):
        comma = ',' if i < n else ''
        lines.append(f"        {{ id: '{prefix}-g3-{i}', chapter: '{esc(ch)}', name: '{esc(name)}', content: '{esc(content)}' }}{comma}")
    return '\n'.join(lines)

shengwu = [
('细胞分子组成与结构', '细胞的分子组成与结构综合', '生命的物质基础：化学元素（大量C/H/O/N/P/S/K/Ca/Mg，微量Fe/Mn/Zn/Cu/B/Mo等）和化合物。<br>元素特点：C是最基本元素；C/H/O/N含量最多；生物界与非生物界统一性（元素种类相同）和差异性（元素含量不同）。<br>水：自由水（良好溶剂/参与生化反应/运输营养废物/提供液体环境）和结合水（细胞结构成分）。自由水/结合水比值越大代谢越旺盛抗逆性越弱。<br>无机盐：以离子形式为主。功能：构成细胞结构成分（Fe血红蛋白/Mg叶绿素/P核酸ATP磷脂/I甲状腺激素）；维持生命活动（Ca抽搐/骨质疏松）；维持渗透压和酸碱平衡（Na+/K+/HCO3-/HPO4^2-）。<br>糖类：单糖（五碳核糖脱氧核糖/六碳葡萄糖果糖半乳糖）、二糖（蔗糖=葡萄糖+果糖/麦芽糖=2葡萄糖/乳糖=葡萄糖+半乳糖）、多糖（淀粉/糖原/纤维素均由葡萄糖缩合而成。淀粉植物储能/糖原动物储能/纤维素植物细胞壁结构/几丁质真菌和昆虫外骨骼）。还原糖（葡萄糖果糖麦芽糖）与斐林试剂反应生成砖红色沉淀（水浴加热）。<br>脂质：脂肪（储能保温缓冲）、磷脂（构成生物膜基本支架）、固醇（胆固醇动物细胞膜/性激素调节/维生素D促Ca吸收）。脂肪用苏丹III（橘黄）/苏丹IV（红色）检验。<br>蛋白质：基本单位氨基酸（20种，结构通式NH2-CHR-COOH）。必需氨基酸8种（人体不能合成必须从食物摄取）。<br>氨基酸脱水缩合形成肽键（-CO-NH-）。n个氨基酸形成m条肽链→脱水n-m个/肽键n-m个/游离氨基和羧基至少各m个。蛋白质相对分子质量=na-18(n-m)（a为氨基酸平均相对分子质量）。<br>蛋白质结构多样性：氨基酸种类/数目/排列顺序不同+多肽链空间结构不同。<br>蛋白质功能多样性：结构蛋白（肌肉/毛发/蛛丝）、催化（酶）、运输（血红蛋白/载体）、调节（胰岛素/生长激素）、免疫（抗体/淋巴因子）、信息传递（受体）。蛋白质用双缩脲试剂检验显紫色。<br>核酸：DNA（脱氧核糖核酸）和RNA（核糖核酸）。基本单位核苷酸（五碳糖+磷酸+含氮碱基）。DNA含脱氧核糖/T（胸腺嘧啶）；RNA含核糖/U（尿嘧啶）。<br>DNA结构：反向平行双螺旋；磷酸和脱氧核糖交替连接构成基本骨架；碱基对通过氢键连接（A-T两个氢键/G-C三个氢键）。<br>核酸功能：携带遗传信息、控制蛋白质合成、表达遗传信息。DNA用甲基绿染绿色；RNA用吡罗红染红色。<br>细胞学说：施莱登/施旺创立。一切动植物由细胞发育而来并由细胞和细胞产物构成；细胞是相对独立的单位；新细胞从老细胞产生。魏尔肖修正：细胞通过分裂产生新细胞。<br>原核细胞与真核细胞：原核（无以核膜为界限的细胞核/无染色体/只有核糖体一种细胞器/有拟核环状DNA。如蓝细菌/大肠杆菌/乳酸菌/硝化细菌/支原体）；真核（有核膜包被的真正细胞核/有染色体和多种复杂细胞器）。<br>细胞膜：磷脂双分子层（基本支架）+蛋白质（功能承担者）+少量糖类（糖蛋白识别/糖脂）。流动镶嵌模型。功能：将细胞与外界分隔开/控制物质进出/进行细胞间信息交流。<br>细胞器：线粒体（有氧呼吸主要场所/动力车间/双层膜含DNA）、叶绿体（光合作用场所/能量转换站/双层膜含DNA）、内质网（蛋白质合成加工/脂质合成车间/单层膜）、高尔基体（蛋白质加工分类包装发送/植物细胞壁形成/动物分泌/单层膜）、核糖体（蛋白质合成场所/无膜结构rRNA+蛋白质）、溶酶体（消化车间/含多种水解酶/单层膜）、中心体（与有丝分裂纺锤体形成有关/无膜/动物和低等植物）、液泡（植物细胞大液泡含细胞液/调节细胞内环境/单层膜）。<br>生物膜系统：细胞膜/核膜/各种细胞器膜共同构成。功能：使细胞有相对稳定内部环境/分隔细胞器保证生命活动高效有序进行/多种化学反应场所。<br>细胞核：核膜（双层膜/有核孔-大分子进出通道）、核仁（与rRNA合成及核糖体形成有关）、染色质（DNA+蛋白质/易被碱性染料染色/与染色体是同一物质不同时期形态）。功能：遗传信息库/细胞代谢和遗传的控制中心。<br>分泌蛋白合成与分泌：核糖体合成肽链→内质网加工折叠→囊泡→高尔基体进一步加工修饰→囊泡→细胞膜胞吐。线粒体提供能量。'),
('细胞代谢', '光合呼吸综合与细胞代谢', '细胞代谢：细胞中全部有序化学反应的总称，是细胞生命活动的基础。<br>酶：活细胞产生的具有催化作用的有机物。绝大多数是蛋白质/少数是RNA。<br>酶特性：高效性（比无机催化剂高10^7~10^13倍）、专一性（一种酶只能催化一种或一类化学反应）、作用条件温和（适宜温度和pH）。<br>酶活性：温度影响（低温抑制/高温失活）；pH影响（过酸过碱失活）。酶最适温度哺乳动物约37℃/植物约25~35℃；胃蛋白酶最适pH约1.5/其他多数约7。<br>ATP（三磷酸腺苷）：结构A-P~P~P（A腺苷=腺嘌呤+核糖/P磷酸基团/~高能磷酸键含大量能量）。功能：细胞生命活动直接能源物质。<br>ATP与ADP相互转化：ATP⇌ADP+Pi+能量。合成能量来源（细胞呼吸/光合作用）；水解能量去向（各种需能生命活动）。<br>细胞呼吸（呼吸作用）：有机物在细胞内氧化分解生成CO2或其他产物释放能量并生成ATP的过程。<br>有氧呼吸三阶段：第一阶段（细胞质基质：葡萄糖→2丙酮酸+4[H]+少量能量）、第二阶段（线粒体基质：2丙酮酸+6H2O→6CO2+20[H]+少量能量）、第三阶段（线粒体内膜：24[H]+6O2→12H2O+大量能量）。<br>有氧呼吸总反应：C6H12O6+6O2+6H2O→6CO2+12H2O+能量。1mol葡萄糖释放约2870kJ，其中约1161kJ储存在约38mol ATP中其余以热能散失。<br>无氧呼吸：细胞质基质中进行。第一阶段同有氧；第二阶段：植物/酵母菌→2酒精+2CO2（酒精发酵）或动物/乳酸菌/马铃薯块茎/玉米胚→2乳酸（乳酸发酵）。无氧呼吸只第一阶段产少量ATP。<br>呼吸作用应用：包扎伤口用透气纱布（抑制破伤风杆菌等厌氧微生物）；酿酒先通气后密封（通气促进酵母菌繁殖/密封促进酒精发酵）；稻田定期排水（防止根无氧呼吸产生酒精中毒烂根）；提倡慢跑（防止乳酸大量积累肌肉酸胀）；果蔬保鲜（零上低温/低氧/高CO2）。<br>光合作用：绿色植物通过叶绿体利用光能把CO2和H2O转化为储存能量的有机物并释放O2的过程。<br>光合色素：类囊体薄膜上。叶绿素a（蓝绿色/主要吸收红光和蓝紫光）、叶绿素b（黄绿色/主要吸收红光和蓝紫光）、胡萝卜素（橙黄色/主要吸收蓝紫光）、叶黄素（黄色/主要吸收蓝紫光）。<br>提取和分离色素实验：提取用无水乙醇（或丙酮）溶解色素；加SiO2研磨充分；加CaCO3防止色素被破坏；分离用纸层析法（色素在层析液中溶解度不同随层析液在滤纸上扩散速度不同）。结果：滤纸条从上到下依次是胡萝卜素/叶黄素/叶绿素a/叶绿素b。<br>光合作用过程：光反应（类囊体薄膜上：水的光解2H2O→4[H]+O2；ADP+Pi→ATP）和暗反应/碳反应（叶绿体基质中：CO2固定CO2+C5→2C3；C3还原2C3+[H]+ATP→(CH2O)+C5+ADP+Pi）。<br>光合作用总反应式：CO2+H2O→(CH2O)+O2（条件光能/叶绿体）或6CO2+12H2O→C6H12O6+6O2+6H2O。<br>C3/C5变化分析：只改变光照→光变弱→ATP和[H]减少→C3还原减少但CO2固定继续→C3增加C5减少；只改变CO2→CO2减少→CO2固定减少→C3减少C5增加。<br>光合作用影响因素：光照强度（光饱和点/光补偿点）、CO2浓度（CO2饱和点/CO2补偿点）、温度（影响酶活性）、水分、矿质元素（N/P/Mg等）。<br>光合速率计算：净光合速率（实际测得）=真光合速率（实际）-呼吸速率。常用单位CO2/mg·h、O2/mL·h、有机物/mg·h。<br>光合呼吸综合：净光合>0积累有机物；净光合<0消耗有机物；净光合=0光合=呼吸。一昼夜有机物积累=白天净积累-夜间呼吸消耗。<br>化能合成作用：少数细菌（硝化细菌/硫细菌/铁细菌）利用体外环境无机物氧化释放的化学能将CO2和H2O合成有机物。属于自养生物。<br>光合作用应用：合理密植（提高光能利用率）、间作套种、轮作、大棚种植（适当提高CO2浓度如增施有机肥/释放干冰/通风；适当提高昼夜温差白天适当升温光合强夜间降温呼吸弱；延长光照时间；选用无色透明塑料）、中耕松土（促进根呼吸有利于矿质吸收）、合理灌溉合理施肥。'),
('细胞生命历程', '有丝减数分裂图像与染色体变化', '细胞增殖：细胞通过分裂进行增殖。意义：生物体生长/发育/繁殖/遗传的基础。方式：有丝分裂/无丝分裂/减数分裂。<br>细胞周期：连续分裂的细胞从一次分裂完成时开始到下一次分裂完成时为止。包括分裂间期（长约90%~95%）和分裂期（M期）。只有连续分裂细胞才有细胞周期（如根尖分生区/茎形成层/皮肤生发层/造血干细胞/癌细胞）。<br>有丝分裂过程：间期（G1/S/G2期完成DNA复制和有关蛋白质合成；染色体数不变DNA数加倍；染色单体出现）；前期（染色质→染色体；核膜核仁消失；纺锤体出现；染色体散乱分布）；中期（染色体着丝点排列在赤道板上；形态固定数目清晰最佳观察期）；后期（着丝点分裂/姐妹染色单体分开/染色体数暂时加倍/纺锤丝牵引向两极移动）；末期（染色体→染色质；核膜核仁重现；纺锤体消失；植物细胞赤道板位置形成细胞板扩展为细胞壁；动物细胞细胞膜内陷缢裂）。<br>各期染色体/DNA/染色单体数变化：设体细胞核DNA数2a染色体数2n→间期（2a→4a/2n/0→4n）；前中期（4a/2n/4n）；后期（4a/4n/0）；末期（2a/2n/0）。<br>有丝分裂意义：亲代细胞染色体复制后精确平均分配到两个子细胞中保证亲代和子代之间遗传性状的稳定性。<br>观察有丝分裂实验：材料（洋葱根尖分生区细胞）；步骤（解离10%盐酸使细胞分离→漂洗清水洗去盐酸防止解离过度→染色龙胆紫或醋酸洋红液→制片压片使细胞分散开）；观察（先低倍找分生区细胞呈正方形排列紧密/再高倍观察）；解离使细胞死亡不能看到连续分裂过程。<br>无丝分裂：核延长缢裂为二/整个细胞从中部缢裂为两个子细胞。无纺锤丝和染色体变化。如蛙的红细胞分裂。<br>减数分裂：有性生殖细胞形成过程中进行的染色体数目减半的细胞分裂。染色体只复制一次而细胞分裂两次。结果：子细胞染色体数减半。<br>同源染色体：形态大小一般相同一条来自父方一条来自母方。减数第一次分裂前期配对联会形成四分体。一个四分体=一对同源染色体=2条染色体=4条染色单体=4个DNA分子。<br>减数第一次分裂：间期（染色体复制）；前期（联会四分体/非姐妹染色单体交叉互换）；中期（四分体排列在赤道板两侧）；后期（同源染色体分离非同源染色体自由组合）；末期（形成两个子细胞染色体数减半无同源）。<br>减数第二次分裂：无同源染色体；前期染色体散乱；中期着丝点排列赤道板；后期着丝点分裂染色体暂时加倍；末期形成四个子细胞。<br>精子形成：1个精原细胞→1个初级精母细胞→2个次级精母细胞→4个精细胞→4个精子（变形成蝌蚪状）。场所：睾丸曲细精管。<br>卵细胞形成：1个卵原细胞→1个初级卵母细胞→1个次级卵母细胞+1个第一极体→1个卵细胞+3个极体（退化消失）。不均等分裂保证卵细胞质丰富营养。场所：卵巢。<br>受精作用：精子和卵细胞识别融合成为受精卵的过程。受精卵细胞核遗传物质一半来自父方一半来自母方；细胞质遗传物质几乎全部来自母方（母系遗传）。减数分裂和受精作用维持生物前后代体细胞染色体数恒定/对遗传和变异重要。<br>细胞分裂图像识别：有同源染色体且联会配对/四分体/同源分离→减数第一次分裂；有同源染色体但无联会配对/着丝点排列/着丝点分裂→有丝分裂；无同源染色体→减数第二次分裂。<br>染色体/DNA变化曲线：有丝分裂染色体曲线（2n→4n→2n后期加倍）DNA曲线（2a→4a→2a间期加倍）；减数分裂染色体曲线（2n→n→2n→n减II后期暂时加倍）DNA曲线（2a→4a→2a→a）。<br>细胞分化：个体发育中由一个或一种细胞增殖产生的后代在形态结构和生理功能上发生稳定性差异的过程。特点：持久性/稳定性/不可逆性/普遍性。<br>细胞全能性：已经分化的细胞仍然具有发育成完整个体的潜能。植物细胞全能性较高（植物组织培养）；动物细胞核具有全能性（动物克隆）；全能性表达条件：离体/一定营养物质/激素/适宜条件。<br>细胞衰老特征：细胞内水分减少/体积变小/新陈代谢速率减慢；多种酶活性降低；色素逐渐积累；呼吸速率减慢/细胞核体积增大/核膜内折/染色质收缩染色加深；细胞膜通透性改变物质运输功能降低。<br>细胞凋亡：由基因决定的细胞自动结束生命的编程性死亡。意义：对个体发育/机体稳定/抵御外界干扰具有重要作用。与细胞坏死（病理性不利）不同。<br>癌细胞特征：无限增殖；形态结构显著变化；细胞膜上糖蛋白等物质减少细胞间黏着性降低易分散转移。致癌因子：物理/化学/病毒致癌因子。癌变机理：原癌基因和抑癌基因发生突变导致细胞周期失控。'),
('遗传基本规律', '分离定律自由组合定律变式', '孟德尔遗传实验：材料豌豆优点（自花传粉闭花受粉自然状态下纯种；相对性状明显易区分；花大易操作）。方法：假说-演绎法。<br>一对相对性状杂交实验：P高茎×矮茎→F1高茎（显性）→F2高茎:矮茎=3:1。<br>对分离现象解释：生物性状由遗传因子（基因）决定；体细胞中遗传因子成对存在；配子形成时成对遗传因子彼此分离；受精时雌雄配子随机结合。<br>验证：测交实验F1×隐性纯合子→后代性状分离比1:1。<br>基因分离定律实质：在减数分裂形成配子时等位基因随同源染色体分开而分离分别进入不同配子中。<br>两对相对性状杂交实验：P黄圆×绿皱→F1黄圆→F2黄圆:黄皱:绿圆:绿皱=9:3:3:1。每一对都遵循分离定律。<br>自由组合定律实质：减数分裂形成配子时非同源染色体上的非等位基因自由组合。<br>遗传基本概念：相对性状/显性性状/隐性性状/性状分离；显性基因/隐性基因/等位基因；表现型/基因型/纯合子/杂合子；杂交/自交/测交/正交/反交。<br>基因型与表现型关系：表现型=基因型+环境。基因型相同表现型可能不同因环境影响。<br>显隐性判断：具相对性状纯合亲本杂交F1表现出来的为显性；相同性状亲本杂交后代出现性状分离则亲本为显性且为杂合子；有中生无为显性无中生有为隐性（系谱图判断）。<br>纯合子杂合子判断：自交法（植物最简便后代性状分离为杂合）；测交法（动物常用后代1:1分离为杂合）；花粉鉴定法（直接观察花粉性状）。<br>9:3:3:1变形分析：9:6:1（显性基因叠加效应）；9:3:4（隐性上位）；12:3:1（显性上位）；15:1（重叠作用只要显性基因即表现一种性状）；9:7（互补作用两对显性基因同时存在才表现显性）；13:3（抑制作用）；1:4:6:4:1（数量遗传显性基因累加效应）。<br>致死问题：显性纯合致死（后代比例2:1而不是3:1）；隐性纯合致死；配子致死；合子致死；性染色体致死。<br>多对等位基因自由组合：n对独立遗传的等位基因→F1配子种类2^n；F2基因型种类3^n；F2表现型种类2^n；F2表现型比例(3:1)^n。<br>遗传定律适用条件：真核生物有性生殖核基因遗传；减数分裂过程中同源染色体分离和非同源自由组合。<br>伴性遗传：基因位于性染色体上遗传与性别相关联。特点：正反交结果不同；后代性状表现与性别有关。<br>XY型性别决定：人/果蝇/哺乳动物等。XX雌性/XY雄性。<br>ZW型性别决定：鸟类/家蚕/蛾蝶类。ZW雌性/ZZ雄性。<br>伴X染色体隐性遗传（红绿色盲/血友病）：男性患者多于女性；交叉遗传（男性→女儿→外孙）；隔代遗传；女性患者父亲和儿子必为患者（女病父子病）。<br>伴X染色体显性遗传（抗维生素D佝偻病）：女性患者多于男性；连续遗传；男性患者母亲和女儿必为患者（男病母女病）。<br>伴Y染色体遗传（外耳道多毛症）：传男不传女；患者父亲和儿子都是患者。<br>系谱图判断技巧：先判显隐性（无中生有为隐性/有中生无为显性）；再判是否伴性（隐性看女患者父子必病为伴X否则常染色体；显性看男患者母女必病为伴X否则常染色体）。<br>基因在染色体上：萨顿假说类比推理法；摩尔根果蝇实验证明基因在染色体上呈线性排列（假说-演绎法）。<br>常染色体与伴性遗传的实验设计：一次杂交实验判断基因位置用隐性雌性×显性雄性（若后代雌性全显雄性全隐为伴X）；未知显隐性时用正反交（结果不同为伴性）。<br>遗传概率计算：加法定理（互斥事件至少一个发生P=P1+P2）；乘法定理（独立事件同时发生P=P1×P2）。<br>遗传病监测和预防：遗传咨询（了解家庭病史→分析传递方式→推算再发风险率→提出对策建议）；产前诊断（羊水检查/B超检查/孕妇血细胞检查/基因诊断）。'),
('基因本质与表达', 'DNA复制转录翻译与中心法则', 'DNA是主要遗传物质证据：肺炎双球菌转化实验（格里菲思体内转化→加热杀死S菌有转化因子；艾弗里体外转化→DNA才是使R菌产生稳定遗传变化的物质）；噬菌体侵染细菌实验（赫尔希蔡斯放射性同位素标记35S标记蛋白质/32P标记DNA→DNA才是真正遗传物质）。<br>肺炎双球菌：R型（粗糙/无荚膜/无毒）；S型（光滑/有荚膜/有毒）。<br>T2噬菌体：DNA+蛋白质外壳。侵染过程：吸附→注入→合成→组装→释放。<br>RNA是遗传物质证据：烟草花叶病毒（TMV）重建实验。DNA病毒（绝大多数）和RNA病毒（HIV/SARS/新冠/流感/烟草花叶病毒）。<br>DNA结构特点：沃森和克里克1953年提出双螺旋结构。反向平行两条脱氧核苷酸链盘旋；磷酸和脱氧核糖交替连接构成基本骨架；碱基互补配对A=T（2氢键）/G≡C（3氢键）。<br>DNA复制：半保留复制（新DNA分子一条母链一条子链）；时间（有丝分裂间期和减数第一次分裂前的间期）；场所（主要细胞核/线粒体叶绿体）；条件（模板亲代DNA两条链/原料四种脱氧核苷酸/能量ATP/酶解旋酶和DNA聚合酶等）；过程（解旋→以母链为模板碱基互补配对合成子链→子链与母链盘绕）；特点（边解旋边复制/半保留复制/多起点双向复制）；意义（将遗传信息从亲代传给子代保持遗传信息连续性）。<br>半保留复制实验证据：大肠杆菌同位素标记15N和14N+密度梯度离心。第一代全中/第二代1/2中1/2轻。<br>DNA复制相关计算：DNA分子数n次复制后为2^n个；含母链的DNA始终2个；脱氧核苷酸链数2^(n+1)条母链2条；某DNA含某种碱基m个则n次复制需游离该碱基(2^n-1)×m个；第n次复制需2^(n-1)×m个。<br>基因是有遗传效应的DNA片段：每个DNA分子上有许多个基因；基因在染色体上呈线性排列；DNA分子蕴藏遗传信息在四种碱基排列顺序中；碱基排列顺序多样性构成DNA分子多样性；碱基特定排列顺序构成特异性。<br>基因表达：DNA（转录）→RNA（翻译）→蛋白质。<br>RNA种类：mRNA（信使RNA传递遗传信息翻译模板）；tRNA（转运RNA识别密码子转运氨基酸三叶草结构）；rRNA（核糖体RNA与蛋白质构成核糖体）。<br>转录：场所（主要细胞核）；模板（DNA一条链即模板链/反义链）；原料（四种核糖核苷酸）；酶（RNA聚合酶）；碱基配对（A-U/T-A/C-G/G-C）；产物（mRNA）；方向5\'→3\'。<br>翻译：场所（核糖体）；模板（mRNA）；原料（20种氨基酸）；搬运工具（tRNA反密码子与mRNA密码子配对）；碱基配对（A-U/U-A/C-G/G-C）；产物（多肽链）；方向5\'→3\'。<br>密码子：mRNA上决定1个氨基酸的3个相邻碱基。共64个密码子→61个编码氨基酸+3个终止密码（UAA/UAG/UGA不编码氨基酸）；起始密码AUG（甲硫氨酸）GUG（缬氨酸）；一种密码子只决定一种氨基酸；一种氨基酸可由多种密码子决定（简并性）；密码子具有通用性（几乎所有生物共用一套密码子）。<br>反密码子：tRNA上与mRNA密码子互补的3个碱基。tRNA共61种（因3个终止无对应tRNA）；一种tRNA识别一种密码子转运一种氨基酸；一种氨基酸可由多种tRNA转运。<br>中心法则：遗传信息传递规律。DNA→DNA（复制）；DNA→RNA（转录）；RNA→蛋白质（翻译）；RNA→RNA（RNA复制某些病毒）；RNA→DNA（逆转录逆转录酶某些病毒如HIV）。<br>原核基因表达：无核膜→边转录边翻译同时进行。<br>真核基因表达：先转录（细胞核内）后翻译（细胞质核糖体）；转录加工（剪切内含子拼接外显子）→成熟mRNA出核。<br>基因表达相关计算：DNA（基因）碱基数:mRNA碱基数:蛋白质氨基酸数≈6:3:1（不考虑终止密码子等）；蛋白质氨基酸数=肽键数+肽链数。<br>基因突变：DNA分子中碱基对的替换/增添/缺失引起基因结构改变。时间（DNA复制时即有丝分裂间期和减数第一次分裂前间期）；原因（内因复制差错；外因物理化学生物因素）；特点（普遍性/随机性/低频性/不定向性/多害少利性）；意义（新基因产生途径/生物变异根本来源/生物进化原始材料）。<br>基因突变类型：碱基替换（点突变只改变1个氨基酸或同义突变）；碱基增添/缺失（移码突变使后面阅读框架改变影响多个氨基酸）。<br>基因突变与性状关系：不一定导致性状改变（密码子简并性/隐性突变/突变发生在非编码区或内含子）。<br>基因重组：生物体进行有性生殖过程中控制不同性状的基因重新组合。类型（减数第一次分裂后期非同源染色体上非等位基因自由组合；减数第一次分裂前期四分体非姐妹染色单体交叉互换；基因工程重组DNA技术）。意义（生物变异重要来源/对生物进化有重要意义）。<br>染色体变异：染色体结构变异（缺失/重复/倒位/易位-非同源染色体之间片段交换不同于交叉互换）；染色体数目变异（个别染色体增减/以染色体组形式成倍增减）。<br>染色体组：细胞中一组形态和功能上各不相同但又互相协调共同控制生物生长发育遗传和变异的非同源染色体。<br>二倍体/多倍体/单倍体：二倍体（由受精卵发育体细胞含两个染色体组如人/果蝇/玉米）；多倍体（受精卵发育含三个或以上染色体组如三倍体无子西瓜/八倍体小黑麦）；单倍体（配子发育体细胞含本物种配子染色体数目如蜜蜂雄蜂/花粉离体培养植株）。<br>单倍体育种：花药（花粉）离体培养获得单倍体→秋水仙素处理萌发的种子或幼苗使染色体加倍→获得纯合正常植株。优点（明显缩短育种年限仅2年）。<br>多倍体育种：用秋水仙素处理萌发的种子或幼苗（抑制纺锤体形成导致染色体不能移向两极细胞不能分裂染色体加倍）。实例：三倍体无子西瓜（二倍体加倍为四倍体×二倍体→三倍体种子种植后减数分裂联会紊乱不能形成种子）。<br>诱变育种：利用物理化学因素处理生物诱发基因突变提高突变率在较短时间获得更多优良变异类型。优点提高突变率创造新类型；缺点盲目性大有利变异少。<br>杂交育种：杂交→自交→选优。原理基因重组。优点操作简便使优良性状集中；缺点育种时间长不能产生新基因。<br>基因工程：按人们意愿提取一种生物某种基因加以修饰改造后放入另一种生物细胞定向改造生物遗传性状。工具（限制酶/DNA连接酶/运载体-质粒/噬菌体/动植物病毒）。步骤（提取目的基因→目的基因与运载体结合→将目的基因导入受体细胞→目的基因的检测与鉴定）。<br>生物进化：拉马克进化学说（用进废退和获得性遗传）；达尔文自然选择学说（过度繁殖/生存斗争/遗传变异/适者生存）；现代生物进化理论（种群是生物进化基本单位/突变和基因重组产生进化原材料/自然选择决定生物进化方向/隔离导致新物种形成）。<br>种群基因频率改变=生物进化。物种形成标志=产生生殖隔离。<br>共同进化与生物多样性：不同物种之间/生物与无机环境之间相互影响中不断进化和发展→共同进化→形成生物多样性（基因多样性/物种多样性/生态系统多样性）。'),
('生命活动调节', '神经体液免疫调节网络', '神经调节基本方式：反射（在中枢神经系统参与下动物体或人体对内外环境变化作出规律性应答）。结构基础：反射弧（感受器/传入神经/神经中枢/传出神经/效应器-传出神经末梢及其支配的肌肉或腺体）。<br>兴奋在神经纤维上传导：静息电位（外正内负K+外流协助扩散）；动作电位（外负内正Na+内流协助扩散）；局部电流→兴奋以电信号形式沿神经纤维双向传导。兴奋传导方向与膜内电流方向一致与膜外相反。<br>兴奋在神经元之间传递：突触（突触前膜/突触间隙/突触后膜）。信号转换：电信号→化学信号（神经递质）→电信号。传递特点：单向（神经递质只由突触前膜释放作用于突触后膜）；突触延搁（比在神经纤维上慢）；易受化学物质影响。<br>神经递质释放方式：胞吐（需要能量体现细胞膜流动性）。作用效果：使下一个神经元兴奋或抑制。递质作用后被酶分解或被回收。<br>神经系统分级调节：下丘脑（体温调节中枢/水盐平衡调节中枢/生物节律/血糖调节）；脑干（呼吸/心血管基本中枢）；小脑（维持身体平衡协调运动）；大脑皮层（调节机体活动最高级中枢）；脊髓（调节躯体运动低级中枢）。<br>大脑皮层高级功能：W区（书写性语言中枢受损失写症）；V区（视觉性语言中枢受损失读症）；S区（运动性语言中枢受损运动性失语症）；H区（听觉性语言中枢受损听觉性失语症）。学习和记忆/情绪/思维等。<br>体液调节：激素等化学物质通过体液传送方式对生命活动进行调节。激素调节是主要内容。<br>激素调节特点：微量和高效/通过体液运输/作用于靶器官靶细胞/作为信使传递信息起调节作用/作用后被灭活。<br>下丘脑-垂体-内分泌腺分级调节和反馈调节：下丘脑分泌促××激素释放激素→垂体分泌促××激素→内分泌腺分泌××激素；××激素过多反过抑制下丘脑和垂体（负反馈）。如甲状腺激素/性激素/肾上腺皮质激素分级调节。<br>常见激素：促甲状腺激素释放激素TRH/促甲状腺激素TSH/甲状腺激素（甲状腺分泌/促进新陈代谢和生长发育尤其中枢神经系统发育和功能/提高神经系统兴奋性/碘缺乏→大脖子病婴幼儿缺乏→呆小症/过多→甲亢）；胰岛素（胰岛B细胞分泌/降低血糖促进组织细胞摄取利用储存葡萄糖抑制肝糖原分解和非糖物质转化/缺乏→糖尿病）；胰高血糖素（胰岛A细胞分泌/升高血糖促进肝糖原分解和非糖物质转化）；生长激素（垂体分泌促进生长主要促进蛋白质合成和骨生长/幼年缺乏→侏儒症幼年过多→巨人症成年过多→肢端肥大症）；肾上腺素（肾上腺髓质分泌/升高血糖加快心跳升高血压）；抗利尿激素ADH（下丘脑合成垂体释放/促进肾小管和集合管对水重吸收/分泌不足→尿崩症）。<br>血糖调节：来源（食物中糖类消化吸收/肝糖原分解/脂肪等非糖物质转化）；去向（氧化分解供能/合成肝糖原和肌糖原/转化为脂肪和某些氨基酸等）。平衡调节：血糖升高→胰岛B细胞分泌胰岛素→血糖降低；血糖降低→胰岛A细胞分泌胰高血糖素/肾上腺分泌肾上腺素→血糖升高。拮抗作用（胰岛素和胰高血糖素）。<br>体温调节：产热（骨骼肌和肝脏）；散热（皮肤毛细血管舒张和汗腺分泌）。寒冷→冷觉感受器→下丘脑体温调节中枢→甲状腺激素/肾上腺素增加（产热增加）/骨骼肌战栗（产热）/毛细血管收缩（散热减少）；炎热→温觉感受器→下丘脑体温调节中枢→毛细血管舒张（散热增加）/汗腺分泌增加（散热）。<br>水盐平衡调节：渗透压升高→下丘脑渗透压感受器→大脑皮层（产生渴觉主动饮水）+垂体释放抗利尿激素→肾小管和集合管重吸收水→尿量减少。<br>神经调节与体液调节关系：不少内分泌腺直接或间接受中枢神经系统调节；内分泌腺分泌的激素可以影响神经系统发育和功能（甲状腺激素）；两者共同协调相辅相成。<br>免疫系统组成：免疫器官（胸腺/骨髓/脾/淋巴结/扁桃体）、免疫细胞（吞噬细胞等淋巴细胞B细胞T细胞）、免疫活性物质（抗体/淋巴因子/溶菌酶）。<br>三道防线：第一道（皮肤黏膜）；第二道（体液中杀菌物质和吞噬细胞）→非特异性免疫先天；第三道（免疫器官和免疫细胞借助血液循环和淋巴循环）→特异性免疫后天。<br>体液免疫：抗原进入机体→吞噬细胞摄取处理→呈递给T细胞→T细胞分泌淋巴因子→B细胞接受抗原刺激并在淋巴因子作用下增殖分化为浆细胞和记忆细胞→浆细胞产生抗体→抗体与抗原特异性结合→形成沉淀或细胞集团→被吞噬细胞吞噬消化。<br>细胞免疫：抗原进入宿主细胞→T细胞接受抗原刺激增殖分化为效应T细胞和记忆细胞→效应T细胞与被抗原入侵的宿主细胞（靶细胞）密切接触→使靶细胞裂解死亡→病原体被抗体结合后消灭。<br>记忆细胞：可在体内长期保留对特定抗原有记忆能力当相同抗原再次入侵快速增殖分化产生更强免疫反应（二次免疫更快更强产生抗体更多）。<br>免疫失调：过敏反应（已免疫机体再次接受相同抗原刺激发生组织损伤或功能紊乱/特点发作迅速反应强烈消退较快一般不破坏组织细胞有明显遗传倾向和个体差异）；自身免疫病（免疫系统异常敏感反应过度敌我不分地将自身物质当作外来异物进行攻击而引起如类风湿性关节炎/系统性红斑狼疮）；免疫缺陷病（HIV引起艾滋病）。<br>HIV：攻击人体T细胞使人体免疫能力几乎全部丧失病人常死于多种病原体感染或恶性肿瘤。传播：性接触/血液/母婴。<br>免疫学应用：疫苗（接种使机体产生记忆细胞预防传染病）；抗原检测（利用抗体特异性检测病原体）；器官移植（免疫抑制剂应用减轻排斥反应）。<br>植物激素调节：生长素（吲哚乙酸IAA）；发现（达尔文实验证明胚芽鞘尖端感光并产生刺激向下传递；鲍森·詹森证明刺激可透过琼脂片；拜尔证明刺激分布不均弯曲；温特命名生长素）。<br>生长素产生/运输/分布：幼嫩芽/叶和发育中种子；极性运输（形态学上端到下端主动运输）；横向运输（单侧光/重力影响）；集中分布在生长旺盛部位。<br>生长素生理作用：两重性（低浓度促进生长高浓度抑制生长甚至杀死植物）；促进扦插枝条生根；促进果实发育（无子番茄）；防止落花落果。不同器官对生长素敏感度不同（根>芽>茎）。<br>顶端优势：顶芽产生生长素向下运输积累在侧芽抑制侧芽生长顶芽优先生长。去除顶芽解除顶端优势。<br>植物激素种类：生长素（促进细胞伸长生长/促进生根/促进果实发育）；赤霉素（促进细胞伸长引起植株增高/促进种子萌发和果实发育）；细胞分裂素（促进细胞分裂延缓衰老）；脱落酸（抑制细胞分裂促进叶和果实衰老和脱落/促进休眠）；乙烯（促进果实成熟促进器官脱落）。<br>植物生长调节剂：人工合成对植物生长发育有调节作用化学物质。如生长素类似物（NAA/2,4-D/IPA/IBA）、赤霉素、乙烯利（释放乙烯）、矮壮素（抑制细胞伸长使植株矮化）。<br>激素间相互作用：协同（生长素和赤霉素都促进细胞伸长）；拮抗（生长素促进生长脱落酸抑制生长；细胞分裂素延缓衰老脱落酸促进衰老）。')
]

